def dynamic_import(mod_path, obj_name=None):
    ''' Take a string and return the corresponding module '''
    try:
        module = __import__(mod_path, fromlist=['whatever'])
    except ImportError, error:
        raise errors.DynamicImportFailed(
            module='.'.join([mod_path, obj_name]), reason=error)
    # Make sure we're up-to-date
    reload(module)

    if obj_name is None:
        obj = module
    elif hasattr(module, obj_name):
        obj = getattr(module, obj_name)
    else:
        raise errors.DynamicImportFailed(
            module='.'.join([mod_path, obj_name]),
            reason='module {} has no attribute {}'.
                   format(module.__name__, obj_name))
        return None

    return obj

def _enforce_no_overlap(self, start_at=0):
        """Enforce that no ranges overlap in internal storage."""
        i = start_at
        while i+1 < len(self.data):
            if self.data[i][1] >= self.data[i+1][0]:
                # beginning of i+1-th range is contained in i-th range
                if self.data[i][1] < self.data[i+1][1]:
                    # i+1-th range is longer, thus enlarge i-th range
                    self.data[i][1] = self.data[i+1][1]

                # removed contained range
                del self.data[i+1]
            i += 1

