def service(self):
        """
        Decrease the countdowns, and remove any expired locks.  Should be called once every <decrease_every> seconds.
        """
        with self.lock:
            # Decrement / remove all attempts
            for key in list(self.attempts.keys()):
                log.debug('Decrementing count for %s' % key)
                if key in self.attempts:
                    if self.attempts[key] <= 1:
                        del self.attempts[key]
                    else:
                        self.attempts[key] -= 1

            # Remove expired locks
            now = datetime.datetime.utcnow()
            for key in list(self.locks.keys()):
                if key in self.locks and self.locks[key] < now:
                    log.info('Expiring login lock for %s' % key)
                    del self.locks[key]

def _init_pathinfo():
    """Return a set containing all existing directory entries from sys.path"""
    d = set()
    for dir in sys.path:
        try:
            if os.path.isdir(dir):
                dir, dircase = makepath(dir)
                d.add(dircase)
        except TypeError:
            continue
    return d

def signal_children(children):
    """Relay interupt/term signals to children, for more solid process cleanup."""
    def terminate_children(sig, frame):
        log = Application.instance().log
        log.critical("Got signal %i, terminating children..."%sig)
        for child in children:
            child.terminate()

        sys.exit(sig != SIGINT)
        # sys.exit(sig)
    for sig in (SIGINT, SIGABRT, SIGTERM):
        signal(sig, terminate_children)

