  );

  fs.writeFileSync(
    `${componentDir}/README_zh-CN.md`,
    `---
title: ${upperComponentName}
subtitle: FIXME 中文名
path: component/${name}
group: FIXME 中文分组名
---

## ${upperComponentName}

简单描述 ${upperComponentName} 组件。

