function encryptGCM(text, keyDerivationInfo, iv) {
    return Promise.resolve().then(() => {
        const ivHex = iv.toString("hex");
        const { rounds } = keyDerivationInfo;
        const encryptTool = crypto.createCipheriv(ENC_ALGORITHM_GCM, keyDerivationInfo.key, iv);
        // Add additional auth data
        encryptTool.setAAD(new Buffer(`${ivHex}${keyDerivationInfo.salt}`, "utf8"));
        // Perform encryption
        let encryptedContent = encryptTool.update(text, "utf8", "base64");
        encryptedContent += encryptTool.final("base64");
        // Handle authentication
        const tag = encryptTool.getAuthTag();
        // Output encrypted components
        return {
            mode: "gcm",
            iv: ivHex,
            salt: keyDerivationInfo.salt,
            rounds,
            content: encryptedContent,
            auth: tag.toString("hex")
        };
    });
}

function toSignatureBaseString(method, url, header_params, query_params) {
    var arr = [];
    var i;

    for (i in header_params) {
        if (header_params[i] !== undefined && header_params[i] !== '') {
            arr.push([encode(i), encode(header_params[i] + '')]);
        }
    }

    for (i in query_params) {
        if (query_params[i] !== undefined && query_params[i] !== '') {
            arr.push([encode(i), encode(query_params[i] + '')]);
        }
    }

    arr = arr.sort(function lexicalSort(a, b) {
        if (a[0] < b[0]) {
            return -1;
        } else if (a[0] > b[0]) {
            return 1;
        } else {
            if (a[1] < b[1]) {
                return -1;
            } else if (a[1] > b[1]) {
                return 1;
            } else {
                return 0;
            }
        }
    }).map(function (el) {
        return el.join("=");
    });

    return [method, encode(url), encode(arr.join('&'))].join('&');
}

function generateConfigureTasks(planner, origin, dest, opts) {

  _.forIn(dest.topology.containers, function(container) {

    var addSubTask = {
      cmd: 'add',
      id: container.id,
      parent: container.containedBy
    };
    var startSubTask = {
      cmd: 'start',
      id: container.id,
      parent: container.containedBy
    };
    var linkSubTask = {
      cmd: 'link',
      id: container.id,
      parent: container.containedBy
    };
    var configureOp = {
      preconditions: containerStatus(container, 'detached'),
      subTasks: [addSubTask, startSubTask, linkSubTask]
    };
    var configureNop = {
      preconditions: containerStatus(container, 'started'),
      subTasks: [{ cmd: 'nop' }]
    };
    var addPreconditions = containerStatus(container, 'detached');
    var linkPreconditions = containerStatus(container, {
      started: true,
      running: false
    });
    var oldContainer = origin.topology.containers[container.id];

    if (oldContainer) {
      // let's detach all removed containers
      oldContainer.contains.filter(function(contained) {
        return container.contains.indexOf(contained) === -1 && !dest.topology.containers[contained];
      }).map(function(contained) {
        // the current contained is NOT included in the dest status
        // so we detach it
        return {
          cmd: 'detach',
          id: contained
        };
      }).reduce(function(list, op) {
        list.push(op);
        return list;
      }, configureNop.subTasks);
    }

    // the children container must be configured before linking
    container.contains.forEach(function(contained) {
      var oldContained = origin.topology.containers[contained];

      linkPreconditions = _.merge(linkPreconditions, containerStatus({
        id: contained,
        containedBy: container.id
      }, 'running'));
      // we need to add those before the link

      if (oldContained && oldContained.containedBy !== container.id) {
        configureOp.subTasks.splice(configureOp.subTasks.length - 1, 0, {
          cmd: 'detach',
          id: contained
        });

        configureNop.subTasks.push({
          cmd: 'detach',
          id: contained
        });
      }

      configureOp.subTasks.splice(configureOp.subTasks.length - 1, 0, {
        cmd: 'configure',
        id: contained
      });

      configureNop.subTasks.push({
        cmd: 'configure',
        id: contained
      });
    });

    if (opts.mode === 'safe' && oldContainer && oldContainer.containedBy !== container.containedBy) {
      // we should unlink the parent before doing anything
      // and link back after
      allParentsIds(origin, container).forEach(function(id) {

        var op = configureOp;
        var nop = configureNop;

        op.subTasks.unshift({
          cmd: 'unlink',
          id: id,
          parent: origin.topology.containers[id].containedBy
        });

        nop.subTasks.unshift({
          cmd: 'unlink',
          id: id,
          parent: origin.topology.containers[id].containedBy
        });

        op.subTasks.push({
          cmd: 'link',
          id: id,
          parent: origin.topology.containers[id].containedBy
        });

        nop.subTasks.push({
          cmd: 'link',
          id: id,
          parent: origin.topology.containers[id].containedBy
        });
      });
    }

    if (opts.mode === 'safe' && configureNop.subTasks.length > 1 && container.containedBy !== container.id) {
      configureNop.subTasks.unshift({
        cmd: 'unlink',
        id: container.id,
        parent: container.containedBy
      });

      configureNop.subTasks.push({
        cmd: 'link',
        id: container.id,
        parent: container.containedBy
      });
    }

    // if a container is already running, there is nothing to do
    planner.addTask({
      cmd: 'configure',
      id: container.id
    }, configureNop);

    // real configure task
    planner.addTask({
      cmd: 'configure',
      id: container.id
    }, configureOp);

    planner.addTask(addSubTask, {
      preconditions: addPreconditions,
      effects: containerStatus(container, 'added')
    });

