        }

        // prepare the store view code
        $this->prepareStoreViewCode();

        // prepare the attribue values
        $attributeOption = $this->initializeAttribute($this->prepareAttributes());

        // insert the attribute option and set the option ID
        $this->setLastOptionId($this->persistAttributeOption($attributeOption));
    }

public function contains($entity)
    {
        if ($entity instanceof ORM_Entity)
        {
            if ($entity->getEntityState() == ORM_Entity::IS_DELETED)
            {
                return false;
            }
            return parent::contains($entity);
        }
        else
        {
            $id = $entity;
            $this->rewind();
            while ($this->valid())
            {
                $entity = $this->current();
                if ($entity->getPrimaryKey() == $id)
                {
                    return true;
                }
                $this->next();
            }
            return false;
        }
    }

