protected function convert_prop( $value, Papi_Core_Conditional_Rule $rule ) {
		$meta_id    = papi_get_meta_id();
		$meta_type  = papi_get_meta_type();
		$entry_type = papi_get_entry_type_by_meta_id( $meta_id, $meta_type );

		if ( ! papi_is_empty( $value ) && $entry_type instanceof Papi_Entry_Type !== false ) {
			$property = $entry_type->get_property( $rule->slug );

			if ( papi_is_property( $property ) ) {
				$prop_value = $property->format_value(
					$value,
					$property->slug,
					$meta_id
				);

				$prop_value = papi_filter_format_value(
					$property->type,
					$prop_value,
					$property->slug,
					$meta_id,
					$meta_type
				);

				$prop_value = $this->get_deep_value(
					$rule->slug,
					$prop_value
				);

				if ( gettype( $prop_value ) === gettype( $rule->value ) ) {
					return $prop_value;
				}
			}

			return $value;
		}

		return $value;
	}

public function addSubscribingHandler(HandlerSubscriberInterface $handler)
    {
        $methods = $handler->getSubscribedMethods();

        foreach ($methods as $method) {
            if (!isset($method['format'], $method['type'], $method['method'])) {
                throw new \RuntimeException(sprintf('For each subscribing method a "type", "format" and "method" attribute must be given, but only got "%s" for %s.', implode('" and "', array_keys($method)), get_class($handler)));
            }

            $this->addHandler($method['type'], $method['format'], array($handler, $method['method']));
        }
    }

public function generateTableSQL($structure) {
        $sql = 'CREATE TABLE' . ' IF NOT EXISTS `' . $structure['table'].'` (' . "\n";

        foreach($structure['columns'] as $column=>$info) {
            if (!is_array($info)) $info = array('type'=>$info);
            if (!isset($info['name'])) $info['name'] = $column;
            if (!empty($info['virtual'])) continue;
            $sql .= $this->generateColumnSQL($info).','."\n";
        }
        if (!empty($structure['indexes'])) {
            foreach($structure['indexes'] as $name=>$info) {
                if (!isset($info['name'])) $info['name'] = $name;
                $sql .= $this->generateIndexSQL($info).','."\n";
            }
        }
        if (!empty($structure['constraints'])) {
            foreach($structure['constraints'] as $info) {
                $info['local_table'] = $structure['table'];
                $sql .= $this->generateConstraintSQL($info).','."\n";
            }
        }
        $sql = substr($sql, 0, -2).')';
        $sql .= ' ENGINE = '.(empty($info['engine']) ? 'INNODB' : $info['engine']).'  CHARACTER SET='.(empty($info['charset']) ? 'utf8' : $info['charset']).' COLLATE='.(empty($info['collate']) ? 'utf8_unicode_ci' : $info['collate']);

        return $sql;
    }

