public function dropDatabase(string $db_name): bool
	{
		if ($this->dropDatabaseStr === false)
		{
			if ($this->db->DBDebug)
			{
				throw new DatabaseException('This feature is not available for the database you are using.');
			}

			return false;
		}
		elseif (! $this->db->query(sprintf($this->dropDatabaseStr, $db_name)))
		{
			if ($this->db->DBDebug)
			{
				throw new DatabaseException('Unable to drop the specified database.');
			}

			return false;
		}

		if (! empty($this->db->dataCache['db_names']))
		{
			$key = array_search(strtolower($db_name), array_map('strtolower', $this->db->dataCache['db_names']), true);
			if ($key !== false)
			{
				unset($this->db->dataCache['db_names'][$key]);
			}
		}

		return true;
	}

public function crawl($config, $filter = null) {
		$pages = [];
		$gcfg  = $config['conf'];
		$cfg   = $config['list'];
		$url   = $config['url'];

		//$cfg['pages']为URL提取规则
		if ($url && $cfg['pages']) {//可以抓取
			$gcfg['ip'] = $this->ip;
			$client     = Curlient::build($gcfg);

			if (isset($cfg['method']) && $cfg['method'] == 'post') {
				$client->request($url, 'post', isset($cfg['data']) ? $cfg['data'] : null);
			} else {
				$client->request($url);
			}

			if (isset($cfg['ajax'])) {
				$client->ajax();
			}

			if (isset($cfg['encoding'])) {
				$encoding = $cfg['encoding'];
			} else if (isset($gcfg['encoding'])) {
				$encoding = $gcfg['encoding'];
			}

			$isJson = false;
			if (isset($cfg['json']) && $cfg['json']) {
				$content = $client->json(isset($encoding) ? $encoding : null);
				$isJson  = true;
			} else {
				$content = $client->text(isset($encoding) ? $encoding : null);
			}
			$cookies = $client->getCookies();
			if ($cookies) {
				$gcfg['cookie'] = isset($gcfg['cookie']) && is_array($gcfg['cookie']) ? @array_merge($gcfg['cookie'], $cookies) : $cookies;
			}
			if ($content) {//解析内容
				if ($isJson) {
					$this->parseJsonData($content, $cfg, $pages, $gcfg, $url);
				} else if (isset($cfg['dom'])) {
					$content = new Crawler($content);
					$this->parseDomData($content, $cfg, $pages, $gcfg, $url);
				} else {
					$this->parseTextData($content, $cfg, $pages, $gcfg, $url);
				}
			}
		}
		$pages = $this->unique($pages);
		if ($cfg['includes']) {
			$pages = $this->includes($pages, $cfg['includes']);
		}
		if ($cfg['excludes']) {
			$pages = $this->excludes($pages, $cfg['excludes']);
		}

		if ($pages) {
			Curlient::goodURL($url, $pages);//完整URL
		}

		if ($pages && $filter) {
			$pages = call_user_func_array($filter, [$pages]);
		}

		return $pages;
	}

public function getFileAsync(
        $share,
        $path,
        GetFileOptions $options = null
    ) {
        Validate::canCastAsString($share, 'share');
        Validate::canCastAsString($path, 'path');

        $method      = Resources::HTTP_GET;
        $headers     = array();
        $postParams  = array();
        $queryParams = array();
        $path        = $this->createPath($share, $path);

        if (is_null($options)) {
            $options = new GetFileOptions();
        }

        $this->addOptionalQueryParam(
            $queryParams,
            Resources::QP_TIMEOUT,
            $options->getTimeout()
        );

        $this->addOptionalHeader(
            $headers,
            Resources::X_MS_RANGE,
            $options->getRangeString() == '' ? null : $options->getRangeString()
        );
        $this->addOptionalHeader(
            $headers,
            Resources::X_MS_RANGE_GET_CONTENT_MD5,
            $options->getRangeGetContentMD5() ? 'true' : null
        );

        $options->setIsStreaming(true);

        return $this->sendAsync(
            $method,
            $headers,
            $queryParams,
            $postParams,
            $path,
            array(Resources::STATUS_OK, Resources::STATUS_PARTIAL_CONTENT),
            Resources::EMPTY_STRING,
            $options
        )->then(function ($response) {
            $metadata = Utilities::getMetadataArray(
                HttpFormatter::formatHeaders($response->getHeaders())
            );

            return GetFileResult::create(
                HttpFormatter::formatHeaders($response->getHeaders()),
                $response->getBody(),
                $metadata
            );
        });
    }

