private function parseAddresses($addresses)
    {
        if (!$addresses) {
            return array();
        }
        if (is_string($addresses)) {
            // old format json string, parse to array
            if ('[' != $addresses[0]) {
                // Expecting a json array, assuming single address
                $address = new Address();
                //todo: parse in id, uuid and type if set
                $address->setIdentifier($addresses);
                $address->setName('');
                $address->setType('email');

                return array($address);
            }
            $addresses = json_decode($addresses, true);
        }

        $res = array();
        foreach ($addresses as $a) {
            $address = new Address();
            //todo: parse in id, uuid and type if set
            $address->setIdentifier($a['identifier']);
            $address->setName($a['name']);
            $address->setType('email');
            $res[] = $address;
        }

        return $res;
    }

public function exec($request)
    {
        assert($request instanceof ARequest);
        /** define local working data */
        $typeCode = $request->getAssetTypeCode();
        $typeId = $request->getAssetTypeId();
        $custId = $request->getCustomerId();
        $isSys = $request->getIsSystem();

        /** perform processing */
        if (is_null($typeId)) {
            /* get type ID by code if missed */
            $typeId = $this->daoTypeAsset->getIdByCode($typeCode);
        }

        /* return cached data for system customer if exists */
        if (
            $isSys &&
            isset($this->cachedSysAccs[$typeId])
        ) {
            $result = $this->cachedSysAccs[$typeId];
        } else {
            /* ... or get data from DB */
            if ($isSys) {
                /* get system customer ID */
                $custId = $this->daoAccount->getSystemCustomerId();
            }
            $account = $this->getAccount($custId, $typeId);
            $result = $this->composeResult($account);
            /* cache data for system customer */
            if ($isSys) {
                $this->cachedSysAccs[$typeId] = $result;
            }
        }

        /** compose result */
        return $result;
    }

