static function encodeParams($str, $key, $operation = 'encode')
    {
        $result = '';
        static $key_cache;
        if (!isset($key_cache[$key])) {
            $key_cache[$key] = md5($key);
        }

        $key = $key_cache[$key];
        if ($operation == 'encode') {
            $str = (string)$str;
        } else {
            //校验数据完整性
            //省略校验要解密的参数是否是一个16进制的字符串
            $str_head = substr($str, 0, 5);
            $str = substr($str, 5);
            if ($str_head != substr(md5($str . $key), 9, 5)) {
                return $result;
            }

            $str = pack('H*', $str);
        }

        if (!$str) {
            return $result;
        }

        for ($str_len = strlen($str), $i = 0; $i < $str_len; $i++) {
            $result .= chr(ord($str[$i]) ^ ord($key[$i % 32]));
        }

        if ($operation == 'encode') {
            $result = bin2hex($result);
            $result = substr(md5($result . $key), 9, 5) . $result;
        }

        return $result;
    }

public function update($data, $predicate, $combination = Predicate\PredicateSet::OP_AND, $validate_datatypes = false)
    {
        $prefixed_table = $this->prefixed_table;

        if ($data instanceof ArrayObject) {
            $d = (array) $data;
        } elseif (is_array($data)) {
            $d = $data;
        } else {
            throw new Exception\InvalidArgumentException(__METHOD__ . ": requires data to be array or an ArrayObject");
        }

        $this->checkDataColumns($d);

        if ($validate_datatypes) {
            $this->validateDatatypes($d);
        }

        $update = $this->sql->update($prefixed_table);
        $update->set($d);
        $update->where($predicate, $combination);

        $result = $this->executeStatement($update);

        return  $result->getAffectedRows();
    }

private function getLibraryInstance($libraryName, $libraryClass) {
        $instance = null;
            $libraryClassName = $this->config->get($libraryName)[$libraryClass];
            if (class_exists($libraryClassName)) {
                if (count(func_get_args()) > 2) {
                    $arguments = array_slice(func_get_args(), 2, count(func_get_args()) - 2);
                    $ref = new \ReflectionClass($libraryClassName);
                    $instance = $ref->newInstanceArgs($arguments);
                    //$instance = new $libraryClassName(array_slice(func_get_args(), 2, count(func_get_args())-2));
                } else {
                    $instance = new $libraryClassName();
                }
                return $instance;
            } else {
                throw new \InvalidArgumentException('Invalid library class(' . $libraryClassName . ')');
            }
        throw new \InvalidArgumentException('We can not instantiate the library class (' . $libraryClassName . ')');
    }

