function validatePackageInfo($info, &$errors, &$warnings, $dir_prefix = '')
    {
        $config      = &PEAR_Config::singleton();
        $packagefile = &new PEAR_PackageFile($config);
        PEAR::staticPushErrorHandling(PEAR_ERROR_RETURN);
        if (strpos($info, '<?xml') !== false) {
            $pf = &$packagefile->fromXmlString($info, PEAR_VALIDATE_NORMAL, '');
        } else {
            $pf = &$packagefile->fromAnyFile($info, PEAR_VALIDATE_NORMAL);
        }

        PEAR::staticPopErrorHandling();
        if (PEAR::isError($pf)) {
            $errs = $pf->getUserinfo();
            if (is_array($errs)) {
                foreach ($errs as $error) {
                    if ($error['level'] == 'error') {
                        $errors[] = $error['message'];
                    } else {
                        $warnings[] = $error['message'];
                    }
                }
            }

            return false;
        }

        return true;
    }

public function getAssignment($roleName, $userId)
    {
        if ($this->isEmptyUserId($userId)) {
            return reject(new Error("User id is empty"));
        }

        return (new Query())->from($this->assignmentTable)
            ->where(['user_id' => (string)$userId, 'item_name' => $roleName])
            ->one($this->db)
            ->then(
                function($row) {
                    return new Assignment([
                        'userId' => $row['user_id'],
                        'roleName' => $row['item_name'],
                        'createdAt' => $row['created_at'],
                    ]);
                },
                function() use ($userId, $roleName) {
                    throw new Error("No assignment found for user '$userId' and role '$roleName'");
                }
            );
    }

public function call(Router $driver, $name = null, array $parameters = [])
    {
        $resolver = $this->resolveDispatchDependencies($driver, $name, $parameters);

        // This would cater request to valid resource but pointing to an
        // invalid child. We should show a 404 response to the user on this
        // case.
        if (! $resolver->isValid()) {
            return false;
        }

        return $this->dispatch($driver, $name, $resolver);
    }

