public function draw($data) {

        // if the data is sane, and the widths have been set (if not calculate them)
        if ($this->dataCheck($data)) {

            // calculate the widths
            $this->calculateWidths($data);

            // if at least one of the columns has header text
            if ($this->hasHeader()) {

                // bold and underscore for the title
                $style = new Style();
                $style->setBold()->setUnderscore();

                $headers = $this->getHeaderText();

                // draw the row of cells
                $this->drawRow($headers, $style);       

            }

            // go through each row of data
            for ($row = 0; $row<count($data); ++$row) {

                // draw the row of cells
                $this->drawRow($data[$row], null);

            }


        }


    }

public function getBackgroundColorIndex()
    {
        if ($this->logicalScreenDescriptor) {
            $index = substr($this->logicalScreenDescriptor, 5, 1);
            $index = unpack('C', $index)[1];

            return $index;
        }

        return 0;
    }

protected function getCalculator(string $shippingMethod): CalculatorInterface
    {
        $method = $this->getMethod($shippingMethod);

        if ($method === null) {
            return false;
        }

        /** @var CalculatorInterface $calculator */
        $calculator = $this->calculatorRegistry->get($method->getCalculator());

        return $calculator;
    }

public function getPagerPersister($name)
    {
        if (!isset($this->nameToServiceIdMap[$name])) {
            throw new \InvalidArgumentException(sprintf('No pager persister was registered for the give name "%s".', $name));
        }

        $serviceId = $this->nameToServiceIdMap[$name];

        $pagerPersister = $this->container->get($serviceId);

        if (!$pagerPersister instanceof PagerPersisterInterface) {
            throw new \LogicException(sprintf(
                'The pager provider service "%s" must implement "%s" interface but it is an instance of "%s" class.',
                $serviceId,
                PagerPersisterInterface::class,
                get_class($pagerPersister)
            ));
        }

        return $pagerPersister;
    }

