public function rollback($inventory_id, $stock_id, $movement_id)
    {
        $item = $this->inventory->find($inventory_id);
        $stock = $this->inventoryStock->find($stock_id);
        $movement = $this->inventoryStockMovement->find($movement_id);

        if ($stock->rollback($movement)) {
            $this->message = 'Successfully rolled back movement';
            $this->messageType = 'success';
            $this->redirect = routeBack('maintenance.inventory.stock.movements.index', [
                $item->id, $stock->id,
            ]);
        } else {
            $this->message = 'There was an error trying to roll back this movement. Please try again.';
            $this->messageType = 'success';
            $this->redirect = routeBack('maintenance.inventory.stock.movements.index', [
                $item->id, $stock->id,
            ]);
        }

        return $this->response();
    }

protected function populateConfig(ArrayObject $config)
    {
        if (!class_exists(\AuthorizeNetAIM::class)) {
            throw new \LogicException('You must install "authorizenet/authorizenet" library.');
        }

        $config->defaults(array(
            'payum.factory_name' => 'authorize_net_aim',
            'payum.factory_title' => 'Authorize.NET AIM',
            'payum.action.capture' => new CaptureAction(),
            'payum.action.status' => new StatusAction(),
            'payum.action.convert_payment' => new ConvertPaymentAction(),
        ));

        if (false == $config['payum.api']) {
            $config['payum.default_options'] = array(
                'login_id' => '',
                'transaction_key' => '',
                'sandbox' => true,
            );
            $config->defaults($config['payum.default_options']);
            $config['payum.required_options'] = array('login_id', 'transaction_key');

            $config['payum.api'] = function (ArrayObject $config) {
                $config->validateNotEmpty($config['payum.required_options']);

                $api = new AuthorizeNetAIM($config['login_id'], $config['transaction_key']);
                $api->setSandbox($config['sandbox']);

                return $api;
            };
        }
    }

